import ReactScrollWheelHandler from "react-scroll-wheel-handler"
import React, {Component} from 'react'
import { Link, Element, Events, animateScroll as scroll, scrollSpy, scroller } from 'react-scroll'
import dat from '../dat.json'

const swipeDuration = 700

export default class Inside extends Component {
    state = {
        inside: dat.inside,
        idx: 0,
        direction: 1,
        moving: true,
        from: 0,
        to: 0,
        hasScrolled: false,
        fade: 1,
        text: 0
    }
    textBlocks = {}

    componentDidMount() {
        Events.scrollEvent.register('begin', (to, _) => {
            this.setState({to, from: this.state.to, fade: 0})
            setTimeout(() => this.setState({
                fade: 1,
                text: to
            }), swipeDuration / 2);
        });
        scrollSpy.update();
        scroller.scrollTo('0', {
            containerId: 'scroller',
        })
    }

    componentWillUnmount() {
        Events.scrollEvent.remove('begin');
    }

    render () {
        console.log(this.state.from, this.state.to)
        return <ReactScrollWheelHandler style={{
            animation: 'fade-in 1s',
        }}
            upHandler={() => {
                scroller.scrollTo(`${Math.max(0, this.state.to - 1)}`,
                {
                    duration: swipeDuration,
                    smooth: 'easeInOutQuint',
                    containerId: 'scroller',
                })
                if(!this.state.hasScrolled) this.setState({ hasScrolled: true})
            }}
            downHandler={() => {
                scroller.scrollTo(`${Math.min(parseInt(this.state.to) + 1, this.state.inside.length - 1)}`,
                {
                    duration: swipeDuration,
                    delay: 10,
                    smooth: 'easeInOutQuint',
                    containerId: 'scroller',
                })
                if(!this.state.hasScrolled) this.setState({ hasScrolled: true})
            }}
        >
            <span style={{
                position: 'fixed',
                bottom: '4vh',
                left: '4vh',
                transition: "opacity 0.3s",
                WebkitTransition: "opacity 0.3s",
                opacity: this.state.hasScrolled ? 0 : .4,
            }}> SCROLL DOWN </span>
            <div style={{
                height: '90vh',
                width: '35%',
                overflow: 'hidden',
                float: 'left',
                position: 'fixed'
            }}>
                <div style={{
                    top: this.state.from * 2.5 + 'em',
                    position: 'absolute',
                    width: '100%',
                    backgroundColor: 'black',
                    opacity: .1,
                    height: '2em',
                    zIndex: -1,
                    transform: `translate(0, ${(this.state.to - this.state.from) * 2.5}em)`,
                    transition: 'all .5s'
                }}/>
                <div style={{ height: '30vh', backgroundColor: 'rgba(0, 0, 0, 0.05)', marginTop: '-.5em', borderRadius: '.2em'}}>
                    {this.state.inside.map(({title}, i) =>
                        <Link style={{cursor: 'pointer'}}
                            containerId='scroller'
                            to={`${i}`}
                            spy={true}
                            smooth='easeInOutQuint'
                            duration={swipeDuration}
                            ignoreCancelEvents={true}
                            key={`link${i}`}>
                            <div style={{
                                margin: '.5em',
                                padding: '.5em',
                                height: '1em',
                                backgroundColor: this.state.section === 2 ? 'white' : ''
                            }}>
                                {title}
                            </div>
                        </Link>
                    )}
                </div>
                {this.state.inside[this.state.text].desc.map((txt, idx) =>
                    <p key={`text${idx}`} style={{
                        margin: '3%',
                        padding: '1%',
                        animationName: this.state.fade === 1 ? 'fade-in' : 'fade-out',
                        animationDuration: `${swipeDuration/2}ms`,
                        animationFillMode: 'forward',
                        backgroundColor: 'rgba(0, 0, 0, 0.03)',
                    }}>
                    {txt}
                </p>
                )}
            </div>

            <div id='scroller' style={{
                width: '80%',
                height: '90vh',
                position: 'relative',
                overflow: 'hidden',
                float: 'right',
            }}>
                <div>
                        {this.state.inside.map(({img}, idx) =>
                            <Element name={`${idx}`} className="element" style={{
                                width: '100%',
                                height: '88vh'
                            }}>
                                <img src={`images/${img}`} style={{
                                    maxHeight: '99%',
                                    float: 'right',
                                    maxWidth: '80%',
                                }}/>

                            </Element>
                        )}
                    </div>
                    <p>Scroll</p>

            </div>
        </ReactScrollWheelHandler>
    }
}