import React from 'react';
import {
    BrowserRouter as Router,
    Switch,
    Route
} from "react-router-dom";
import Nav from './components/nav';
import dat from './dat.json'
import './App.css';

export default function App() {
    dat.gallery.forEach((e, i) => {
        var img = new Image()
        img.src = '/images/' + e
        img.id = 'gal_preload_' + i
        img.loading = 'eager'
    })

    return (
        <Router>
            <div className="app">
                <Switch>
                    <Route path="/">
                        <Nav />
                    </Route>
                </Switch>
            </div>
        </Router>
    );
}
