import  React, { Component } from 'react';
import { Home } from './home';
import Gallery from './gallery';
import Inside from './inside';
import { withRouter } from 'react-router-dom';

class Nav extends Component {
    state = {
        page: window.location.href.split('https://localhost:3000/')[1]
    }

    components = {
        home : React.createElement(Home),
        Home : React.createElement(Home),
        gallery : React.createElement(Gallery),
        Gallery : React.createElement(Gallery),
        inside : React.createElement(Inside),
        Inside : React.createElement(Inside),
    }

    t = 0

    componentDidMount() {
        if (!this.state.page) this.setState({page: 'Home'})
    }

    render() {
        this.t = 0

        return <div style={{  overflow: 'hidden'}}>
            <div style={{
                position: 'fixed',
                top: 0,
                width: '100vw',
                zIndex: 5,
                height: '10vh',
                lineHeight: '10vh',
                paddingLeft: '5vw',
                fontSize: '1.5em',
                backgroundColor: 'white'
            }}>
                {this.createNavItem('STRATA', 0, 'Home')}
                {this.createNavItem('GALLERY', 1, 'Gallery')}
                {this.createNavItem('INSIDE', 2, 'Inside')}
            </div>
            <div style={{height: '10vh'}} />
            {this.components[this.state.page]}
        </div>
    }

    createNavItem(name, idx, to) {
        this.t += .3
        return <div style={{
            float: 'left',
            fontSize: '.7em',
            width: '15%',
            opacity: this.state.hovered === idx ? '85%' : '50%',
            textDecoration: "none",
            color: 'black',
            cursor: 'pointer'
        }}
            onMouseEnter={() => this.setState({hovered: idx})}
            onMouseLeave={() => this.setState({hovered: null})}
            onClick={() => {
                this.setState({page: to})
                this.props.history.push(to)
            }}
        >
                <div className='nav_item' style={{
                    animationDuration: '1s',
                    animationDelay: `${this.t}s`,
                    animationName: 'fade-in',
                    animationFillMode: 'both'
                }}>
                    {name}
                </div>
        </div>
    }
}

export default withRouter(Nav);